#{disId} AS disId,
#{startDate} AS startDate,
#{stopDate} AS stopDate,
IFNULL((
    select SUM(ndpg.nx_DPG_buy_subtotal)
    from nx_distributer_purchase_goods as ndpg
    left join nx_distributer_purchase_batch as ndpb on ndpb.nx_distributer_purchase_batch_id = ndpg.nx_DPG_batch_id
    where ndpg.nx_DPG_dis_goods_id = dg.nx_distributer_goods_id
    and ndpg.nx_DPG_distributer_id = #{disId}
    and ndpg.nx_DPG_status > #{dayuStatus}

        and (ndpg.nx_DPG_purchase_type is null OR ndpg.nx_DPG_purchase_type != #{purchaseTypeNotEqual})


        and (ndpg.nx_DPG_batch_id is null OR ndpb.nx_DPB_purchase_type = 13)


        and ndpb.nx_DPB_purchase_type = 12


        and ndpg.nx_DPG_batch_id = #{batchId}


        and ndpg.nx_DPG_pur_user_id = #{purUserId}


        and ndpg.nx_DPG_sell_user_id = #{sellUserId}


        and ndpg.nx_DPG_purchase_date >= #{startDate}


        and ndpg.nx_DPG_purchase_date <= #{stopDate}

), 0) AS sellSubtotal
from nx_distributer_goods as dg

    left join nx_distributer_father_goods as ndfg on ndfg.nx_distributer_father_goods_id = dg.nx_dg_dfg_goods_grand_id

where dg.nx_distributer_goods_id in (
    select distinct ndpg.nx_DPG_dis_goods_id 
    from nx_distributer_purchase_goods as ndpg
    left join nx_distributer_purchase_batch as ndpb on ndpb.nx_distributer_purchase_batch_id = ndpg.nx_DPG_batch_id

