SELECT g.nx_dg_goods_name, g.nx_dg_goods_standardname, g.nx_dg_goods_brand, g.nx_dg_goods_standard_weight, g.nx_dg_goods_file, g.nx_dg_goods_file_large, g.nx_dg_carton_unit, g.nx_dg_items_per_carton, t.goods_id AS nx_distributer_goods_id, t.times AS nxDgQuantityDays FROM ( SELECT nx_DPG_dis_goods_id AS goods_id, COUNT(*) AS times FROM nx_distributer_purchase_goods WHERE nx_DPG_purchase_date BETWEEN #{startDate} AND #{stopDate} AND nx_DPG_distributer_id = #{disId} AND nx_DPG_status > 2 AND nx_DPG_buy_subtotal > 0
AND nx_DPG_purchase_type != #{purchaseTypeNotEqual}
AND nx_DPG_purchase_user_id IN
#{userId}
AND nx_DPG_purchase_nx_supplier_id IN
#{supplierId}
GROUP BY nx_DPG_dis_goods_id ) t JOIN nx_distributer_goods g ON g.nx_distributer_goods_id = t.goods_id ORDER BY t.times DESC LIMIT 10

SELECT g.nx_dg_goods_name, g.nx_dg_goods_standardname, g.nx_dg_goods_brand, g.nx_dg_goods_standard_weight, g.nx_dg_goods_file, g.nx_dg_goods_file_large, g.nx_dg_carton_unit, g.nx_dg_items_per_carton, t.goods_id AS nx_distributer_goods_id, t.total_subtotal AS goodsPurTotalSubtotal FROM ( SELECT nx_DPG_dis_goods_id AS goods_id, ROUND(SUM(nx_DPG_buy_subtotal), 1) AS total_subtotal FROM nx_distributer_purchase_goods WHERE nx_DPG_purchase_date BETWEEN #{startDate} AND #{stopDate} AND nx_DPG_distributer_id = #{disId} AND nx_DPG_status > 2 AND nx_DPG_buy_subtotal > 0
AND nx_DPG_purchase_type != #{purchaseTypeNotEqual}
AND nx_DPG_purchase_user_id IN
#{userId}
AND nx_DPG_purchase_nx_supplier_id IN
#{supplierId}
GROUP BY nx_DPG_dis_goods_id ) t JOIN nx_distributer_goods g ON g.nx_distributer_goods_id = t.goods_id ORDER BY t.total_subtotal DESC LIMIT 10

SELECT ROUND(SUM(total_subtotal), 1) AS top10Subtotal
FROM (
         SELECT nx_DPG_dis_goods_id,
                ROUND(SUM(nx_DPG_buy_subtotal), 1) AS total_subtotal
         FROM nx_distributer_purchase_goods
         WHERE nx_DPG_purchase_date BETWEEN #{startDate} AND #{stopDate}
           AND nx_DPG_distributer_id = #{disId}
           AND nx_DPG_status > 2
           AND nx_DPG_buy_subtotal > 0

           AND nx_DPG_purchase_type != #{purchaseTypeNotEqual}


           AND nx_DPG_purchase_user_id IN

               #{userId}



           AND nx_DPG_purchase_nx_supplier_id IN

               #{supplierId}


         GROUP BY nx_DPG_dis_goods_id
         ORDER BY total_subtotal DESC
         LIMIT 10
     ) t

SELECT g.nx_dg_goods_name, g.nx_dg_goods_standardname, g.nx_dg_goods_brand, g.nx_dg_goods_standard_weight, g.nx_dg_goods_file, g.nx_dg_goods_file_large, g.nx_dg_carton_unit, g.nx_dg_items_per_carton, t.goods_id AS nx_distributer_goods_id, t.max_price AS nxDgGoodsHighestPrice, t.min_price AS nxDgGoodsLowestPrice, t.price_diff AS goodsPriceDiff, t.price_fluctuation AS goodsPriceFluctuation FROM ( SELECT nx_DPG_dis_goods_id AS goods_id, MAX(CAST(nx_DPG_buy_price AS DECIMAL(10, 1))) AS max_price, MIN(CAST(nx_DPG_buy_price AS DECIMAL(10, 1))) AS min_price, ROUND((MAX(CAST(nx_DPG_buy_price AS DECIMAL(10, 1))) - MIN(CAST(nx_DPG_buy_price AS DECIMAL(10, 1)))), 1) AS price_diff, ROUND(((MAX(CAST(nx_DPG_buy_price AS DECIMAL(10, 1))) - MIN(CAST(nx_DPG_buy_price AS DECIMAL(10, 1)))) / MIN(CAST(nx_DPG_buy_price AS DECIMAL(10, 1)))) * 100, 1) AS price_fluctuation FROM nx_distributer_purchase_goods WHERE nx_DPG_purchase_date BETWEEN #{startDate} AND #{stopDate} AND nx_DPG_distributer_id = #{disId} AND nx_DPG_buy_price IS NOT NULL AND nx_DPG_status > 2
AND nx_DPG_purchase_type != #{purchaseTypeNotEqual}
AND nx_DPG_purchase_user_id IN
#{userId}
AND nx_DPG_purchase_nx_supplier_id IN
#{supplierId}
GROUP BY nx_DPG_dis_goods_id ) t JOIN nx_distributer_goods g ON g.nx_distributer_goods_id = t.goods_id ORDER BY t.price_fluctuation DESC LIMIT 10
